import{_ as o,H as a,f as l,i as t}from"./chunks/framework.DzzgwZ9Y.js";const h=JSON.parse('{"title":"兼容范围（Cobra v1.x）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/reference/compat.md","filePath":"zh/reference/compat.md"}'),i={name:"zh/reference/compat.md"};function r(s,e,c,d,n,p){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="兼容范围-cobra-v1-x" tabindex="-1">兼容范围（Cobra v1.x） <a class="header-anchor" href="#兼容范围-cobra-v1-x" aria-label="Permalink to &quot;兼容范围（Cobra v1.x）&quot;">​</a></h1><p>本项目对 “Cobra parity” 的定义是：给定同一棵命令树 + argv，Clasp 尽量匹配 Cobra v1.x 的<strong>可观测 CLI 行为</strong>（而不是复制 Go API surface）。</p><h2 id="must-support-兼容契约" tabindex="-1">Must Support（兼容契约） <a class="header-anchor" href="#must-support-兼容契约" aria-label="Permalink to &quot;Must Support（兼容契约）&quot;">​</a></h2><p>这些属于“兼容性承诺”：调整行为应补齐对应 example + CTest。</p><ul><li>命令树：子命令、aliases、hidden/deprecated、groups、suggestions</li><li>hooks：persistent + local（继承与顺序）</li><li>args validators：NoArgs/Exact/Min/Max/Range</li><li>flags：persistent vs local、required/hidden/deprecated、group constraints、重复 flags、NoOptDefVal</li><li>解析语义：<code>--k=v</code>、<code>-k v</code>、<code>-k=v</code>、<code>-abc</code>、<code>-ovalue</code>、<code>--no-foo</code>、<code>NoOptDefVal</code>、<code>--</code></li><li>help/usage/version：<code>--help/-h</code>、<code>help [cmd]</code>、default values 展示、排序开关、examples</li><li>completion：bash/zsh/fish/powershell + <code>__complete</code> candidates + directives</li><li>外部源合并：<code>flag &gt; env &gt; config &gt; default</code></li></ul><h2 id="should-support-best-effort" tabindex="-1">Should Support（Best-Effort） <a class="header-anchor" href="#should-support-best-effort" aria-label="Permalink to &quot;Should Support（Best-Effort）&quot;">​</a></h2><p>这些对 “Cobra-like feel” 很重要，但暂时不作为严格 contract（除非 CTest 锁定）：</p><ul><li>Cobra 默认英文文案/空白的逐字节一致</li><li>更“怪”的 pflag edge cases（排序、错误文案细节、罕见交互）</li><li>completion 脚本在 shell/runtime 中体现的细节差异（Clasp 只输出 directives）</li></ul><h2 id="non-goals-明确不追" tabindex="-1">Non-Goals（明确不追） <a class="header-anchor" href="#non-goals-明确不追" aria-label="Permalink to &quot;Non-Goals（明确不追）&quot;">​</a></h2><ul><li>Go template 语言等价（Clasp 仅做占位符替换 + 完全覆盖函数）</li><li>复制 Cobra/pflag 的全部 Go API surface（<code>*pflag.FlagSet</code> 等）</li><li>完整 pflag 类型面（可通过 <code>clasp::Value</code> 扩展）</li><li>完整 Viper drop-in</li></ul><h2 id="已知差异-当前可接受" tabindex="-1">已知差异（当前可接受） <a class="header-anchor" href="#已知差异-当前可接受" aria-label="Permalink to &quot;已知差异（当前可接受）&quot;">​</a></h2><ul><li>模板语言能力受限（无条件/循环/管道/func）</li><li><code>--help/-h</code> 与 <code>--version</code> 作为内建 flags（即使未显式声明）</li><li>内建类型面是子集（<code>bool/int/int64/uint64/float/double/duration/string</code> + 若干 helpers）</li><li>completion 细节依赖 shell/runtime</li><li>错误文案不保证逐字节一致（除非用 CTest 锁定）</li></ul><h2 id="把-best-effort-变成-contract-的推荐流程" tabindex="-1">把 best-effort 变成 contract 的推荐流程 <a class="header-anchor" href="#把-best-effort-变成-contract-的推荐流程" aria-label="Permalink to &quot;把 best-effort 变成 contract 的推荐流程&quot;">​</a></h2><ol><li>在 <code>examples/</code> 增加复现/示例</li><li>在 <code>CMakeLists.txt</code> 增加 CTest 断言（锁定输出/exit code/关键语义）</li><li>实现行为并保证跨平台一致（macOS/Linux/Windows）</li></ol>',14)])])}const f=o(i,[["render",r]]);export{h as __pageData,f as default};
